package com.anvritai.abhay.api;import com.anvritai.abhay.security.UserPrincipal;import com.anvritai.abhay.service.GlobalSearchService;import java.util.UUID;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/companies/{companyId}/search") public class SearchController{private final GlobalSearchService service;public SearchController(GlobalSearchService s){service=s;}@GetMapping public SearchDtos.SearchResponse search(@AuthenticationPrincipal UserPrincipal p,@PathVariable UUID companyId,@RequestParam String q,@RequestParam(defaultValue="25")int limit){return service.search(p.id(),companyId,q,limit);}}
